// Route email by type based on subject line
// - New bookings: subject contains "New purchase"
// - Cancellations/refunds: subject contains "cancel" or "refund"
// - Unknown: anything else from feverup that mentions Fever

const subject = ($json.subject || '').trim().toLowerCase();

let emailType = 'unknown';

if (subject.includes('new purchase')) {
  emailType = 'new_booking';
} else if (subject.includes('cancel') || subject.includes('refund')) {
  emailType = 'cancellation';
}

return {
  json: {
    ...$json,
    email_type: emailType
  }
};

// Parse FEVER email to extract purchase data
// Subject format: "New purchase with Fever for your event {EVENT_NAME}"
// Email body/summary contains: "{Name} x {qty} {DD/M/YYYY} {time} {price} AUD"
// Hidden preview span contains: "{qty} tickets | {DD/M/YYYY}"
//
// Examples:
//   Subject: "New purchase with Fever for your event iD Comedy Club - Friday & Saturday Nights"
//   Body text: "Mia Tran x 2 26/6/2026 7:00 pm 70.0 AUD"
//   Body text: "Kathy May x 1 21/2/2026 7:00 pm 35.0 AUD"
//   Body text: "Carmen Dom x 2 18/3/2026 7:00 pm 60.0 AUD"

const subject = ($json.subject || '').trim();
const htmlBody = ($json.html || $json.textHtml || '').toString();
const textBody = ($json.text || $json.textPlain || '').toString();

// 1. Extract event name from subject
const eventNameMatch = subject.match(/for your event\s+(.+)$/i);
const eventName = eventNameMatch ? eventNameMatch[1].trim() : subject;

// 2. Parse the purchase data from body text
// Try multiple sources: plain text body, HTML body stripped of tags, summary text
// The pattern is: {Name} x {qty} {DD/M/YYYY} {H:MM am/pm} {price} AUD
const bodyText = textBody || htmlBody.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ');

// Regex: Name (words/spaces) x qty date time price AUD
// Name can contain letters, spaces, hyphens, apostrophes
// Date is DD/M/YYYY (day and month may or may not be zero-padded)
// Time is H:MM am/pm (with possible space before am/pm)
// Price is a decimal number
const purchaseRegex = /([A-Za-z][A-Za-z '.\-]+?)\s+x\s+(\d+)\s+(\d{1,2}\/\d{1,2}\/\d{4})\s+(\d{1,2}:\d{2}\s*[ap]m)\s+([\d.]+)\s*AUD/i;
const purchaseMatch = bodyText.match(purchaseRegex);

if (!purchaseMatch) {
  throw new Error(`Could not parse FEVER purchase data from email body. Subject: ${subject}. Body preview: ${bodyText.substring(0, 300)}`);
}

const customerFullName = purchaseMatch[1].trim();
const ticketCount = parseInt(purchaseMatch[2], 10);
const rawDate = purchaseMatch[3];       // DD/M/YYYY
const rawTime = purchaseMatch[4].trim(); // H:MM pm
const grossRevenue = parseFloat(purchaseMatch[5]);

// 3. Split customer name into first/last
const nameParts = customerFullName.split(/\s+/);
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

// 4. Convert date DD/M/YYYY → YYYY-MM-DD
const dateParts = rawDate.split('/');
let eventDate = rawDate;
if (dateParts.length === 3) {
  const day = dateParts[0].padStart(2, '0');
  const month = dateParts[1].padStart(2, '0');
  const year = dateParts[2];
  eventDate = `${year}-${month}-${day}`;
}

// 5. Generate synthetic booking reference for dedup
// Format: FEVER-{firstnamelastname}-{YYYY-MM-DD}
const nameSlug = (firstName + lastName).toLowerCase().replace(/[^a-z0-9]/g, '');
const bookingReference = `FEVER-${nameSlug}-${eventDate}`;

// 6. Generate synthetic email for CRM (FEVER doesn't provide customer email)
const syntheticEmail = `fever.${firstName.toLowerCase().replace(/[^a-z]/g, '')}.${lastName.toLowerCase().replace(/[^a-z]/g, '')}@placeholder.local`;

return {
  json: {
    event_name: eventName,
    first_name: firstName,
    last_name: lastName,
    email: syntheticEmail,
    ticket_count: isNaN(ticketCount) ? 1 : ticketCount,
    event_date: eventDate,
    event_time: rawTime,
    gross_revenue: isNaN(grossRevenue) ? 0 : grossRevenue,
    booking_reference: bookingReference,
    source_email_subject: subject,
    source_email_date: $json.date || ''
  }
};

// Merge the parsed FEVER data with the matched event/session
const parsed = $('Parse FEVER Email Body').item.json;
const matchResult = $input.item.json;

// The RPC returns an array - take the first match
const match = Array.isArray(matchResult) ? matchResult[0] : matchResult;

if (!match || !match.event_id) {
  return {
    json: {
      ...parsed,
      event_id: null,
      session_id: null,
      match_status: 'no_match',
      match_message: `No event found matching: ${parsed.event_name} on ${parsed.event_date}`
    }
  };
}

return {
  json: {
    ...parsed,
    event_id: match.event_id,
    session_id: match.session_id || null,
    match_status: 'matched',
    match_message: `Matched to event: ${match.event_name || match.event_id}`
  }
};

// Prepare the final payload for manual_ticket_entries
const attendee = $('Merge Match Data').item.json;
const customerResult = $input.item.json;

// Get customer_id from upsert result
const customer = Array.isArray(customerResult) ? customerResult[0] : customerResult;
const customerId = customer?.id || null;

// FEVER Partner ID
const FEVER_PARTNER_ID = '155dfe4f-7132-4f23-8179-1389a667b0dd';

return {
  json: {
    event_id: attendee.event_id,
    session_id: attendee.session_id,
    partner_id: FEVER_PARTNER_ID,
    ticket_count: attendee.ticket_count,
    gross_revenue: attendee.gross_revenue,
    commission_rate: 20,
    entry_date: attendee.event_date || new Date().toISOString().split('T')[0],
    first_name: attendee.first_name,
    last_name: attendee.last_name,
    email: attendee.email,
    booking_reference: attendee.booking_reference,
    customer_id: customerId,
    source: 'n8n',
    status: 'confirmed',
    notes: `FEVER import: ${attendee.event_name}`,
    reference_id: attendee.booking_reference
  }
};

// Parse FEVER cancellation/refund email to extract customer + event info
// We need to reconstruct the synthetic booking reference: FEVER-{firstlast}-{YYYY-MM-DD}
// to look up and cancel the matching entry.
//
// Cancellation emails may vary in format. We attempt to extract:
// - Customer name
// - Event name
// - Event date
// from the email body.

const subject = ($json.subject || '').trim();
const htmlBody = ($json.html || $json.textHtml || '').toString();
const textBody = ($json.text || $json.textPlain || '').toString();

const bodyText = textBody || htmlBody.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ');

// Try to extract event name from subject (same pattern as purchase emails)
const eventNameMatch = subject.match(/for your event\s+(.+)$/i);
const eventName = eventNameMatch ? eventNameMatch[1].trim() : '';

// Try to extract customer name and date from body
// Pattern: "{Name} x {qty} {DD/M/YYYY}" or similar
const cancelRegex = /([A-Za-z][A-Za-z '.\-]+?)\s+x\s+\d+\s+(\d{1,2}\/\d{1,2}\/\d{4})/i;
const cancelMatch = bodyText.match(cancelRegex);

let firstName = '';
let lastName = '';
let eventDate = '';
let bookingReference = '';

if (cancelMatch) {
  const customerFullName = cancelMatch[1].trim();
  const nameParts = customerFullName.split(/\s+/);
  firstName = nameParts[0] || '';
  lastName = nameParts.slice(1).join(' ') || '';

  // Convert date DD/M/YYYY → YYYY-MM-DD
  const rawDate = cancelMatch[2];
  const dateParts = rawDate.split('/');
  if (dateParts.length === 3) {
    const day = dateParts[0].padStart(2, '0');
    const month = dateParts[1].padStart(2, '0');
    const year = dateParts[2];
    eventDate = `${year}-${month}-${day}`;
  } else {
    eventDate = rawDate;
  }

  // Reconstruct the synthetic booking reference
  const nameSlug = (firstName + lastName).toLowerCase().replace(/[^a-z0-9]/g, '');
  bookingReference = `FEVER-${nameSlug}-${eventDate}`;
}

if (!bookingReference) {
  throw new Error(`Could not parse FEVER cancellation data from email. Subject: ${subject}. Body preview: ${bodyText.substring(0, 300)}`);
}

return {
  json: {
    booking_reference: bookingReference,
    first_name: firstName,
    last_name: lastName,
    event_date: eventDate,
    event_name: eventName,
    source_email_subject: subject,
    source_email_date: $json.date || ''
  }
};

// Handle results - log success/failure counts for both bookings and cancellations
const items = $input.all();
let inserted = 0;
let cancelled = 0;
let duplicates = 0;
let notFound = 0;
let errors = 0;

for (const item of items) {
  const statusCode = item.json.statusCode || item.json?.headers?.status;
  const body = item.json.body || item.json;

  if (statusCode === 201) {
    inserted++;
  } else if (statusCode === 200) {
    // PATCH returns 200 - check if any rows were actually updated
    const resultArray = Array.isArray(body) ? body : [];
    if (resultArray.length > 0) {
      cancelled++;
    } else {
      notFound++;
    }
  } else if (statusCode === 409) {
    duplicates++;
  } else {
    errors++;
  }
}

return {
  json: {
    summary: 'FEVER Import Complete',
    inserted: inserted,
    cancelled: cancelled,
    duplicates_skipped: duplicates,
    cancellation_not_found: notFound,
    errors: errors,
    total_processed: items.length,
    timestamp: new Date().toISOString()
  }
};
